glsl.vertex:
varying vec2 vUv;
void main(){
 vUv = uv;
 gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}

glsl.fragment:
precision mediump float;
varying vec2 vUv;
uniform float u_time;
float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453); }
float noise(vec2 p){ vec2 i=floor(p); vec2 f=fract(p); vec2 u=f*f*(3.0-2.0*f); return mix(mix(hash(i), hash(i+vec2(1.0,0.0)), u.x), mix(hash(i+vec2(0.0,1.0)), hash(i+vec2(1.0,1.0)), u.x), u.y); }
void main(){
 vec2 uv = vUv;
 float bands = smoothstep(0.02, 0.98, uv.y);
 vec3 paper = vec3(0.918, 0.846, 0.742);
 vec3 rose = vec3(0.782, 0.466, 0.560);
 vec3 blue = vec3(0.160, 0.390, 0.480);
 vec3 pale = mix(paper, rose, 0.18 + 0.14 * sin(uv.y * 18.849));
 vec3 sea = mix(pale, blue, smoothstep(0.08, 0.42, uv.y) * (1.0 - smoothstep(0.64, 0.92, uv.y)) * 0.42);
 float grain = noise(uv * vec2(92.0, 58.0)) * 0.08 + noise(uv * vec2(19.0, 31.0)) * 0.05;
 float brush = sin((uv.x + noise(uv * 6.0) * 0.045) * 34.0) * 0.018;
 vec3 color = sea + grain + brush;
 color *= 0.92 + 0.08 * bands;
 gl_FragColor = vec4(color, 1.0);
}
